use std::error::Error;
use std::fmt;

struct ModConfig {
    base_logic: bool,
    expansion_a_enabled: bool,
    expansion_b_enabled: bool,
}

impl Default for ModConfig {
    fn default() -> Self {
        ModConfig {
            base_logic: true,
            expansion_a_enabled: false,
            expansion_b_enabled: false,
        }
    }
}

struct GameError(String);
impl fmt::Display for GameError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Game Error: {}", self.0)
    }
}
impl Error for GameError {}

fn run_mod_update(config: ModConfig) -> Result<(), Box<dyn Error>> {
    if !config.base_logic {
        return Err(Box::new(GameError("Base logic is disabled.".to_string())));
    }

    println!("Running core game initialization routines...");

    #[cfg(feature = "expansion_a")]
    if config.expansion_a_enabled {
        println!("Initializing Expansion A module for advanced particle effects.");
    }

    #[cfg(feature = "expansion_b")]
    if config.expansion_b_enabled {
        println!("Loading Extension B resource pack and scripts.");
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let initial_config = ModConfig::default();
    run_mod_update(initial_config)?;
    Ok(())
}

use std::collections::HashMap;

struct ConfigManager {
    base_paths: HashMap<String, String>,
}

impl ConfigManager {
    fn new() -> Self {
        let mut paths = HashMap::new();
        paths.insert("default".to_string(), "/etc/app".to_string());
        ConfigManager { base_paths: paths }
    }

    #[cfg(target_os = "linux")]
    fn build_for_systems(&self) -> Result<(), String> {
        println!("Running Linux-specific setup for system directories.");
        Ok(())
    }

    #[cfg(target_os = "macos")]
    fn build_for_apple(&self) -> Result<(), String> {
        println!("Running macOS-specific setup using user libraries.");
        Ok(())
    }

    #[cfg(not(any(target_os = "linux", target_os = "macos")))]
    fn build_for_other(&self) -> Result<(), String> {
        println!("Running generic setup for unsupported targets.");
        Ok(())
    }

    fn initialize(&self) -> Result<(), String> {
        #[cfg(target_os = "linux")]
        { self.build_for_systems()?; }
        #[cfg(target_os = "macos")]
        { self.build_for_apple()?; }
        #[cfg(not(any(target_os = "linux", target_os = "macos")))]
        { self.build_for_other()?; }
        Ok(())
    }
}

fn main() {
    let manager = ConfigManager::new();
    match manager.initialize() {
        Ok(_) => println!("Configuration initialization complete."),
        Err(e) => eprintln!("Failed to initialize configuration: {}", e),
    }
}

use std::collections::HashMap;

struct SystemComponent {
    name: String,
    config_flags: HashMap<String, bool>,
}

impl SystemComponent {
    fn new(name: &str, flags: HashMap<String, bool>) -> Self {
        SystemComponent {
            name: name.to_string(),
            config_flags: flags,
        }
    }

    fn setup(&self) -> Result<(), String> {
        if *self.config_flags.get("build_web").unwrap_or(&false) {
            println!("Web initialization logic executed for {}", self.name);
            Ok(()) 
        } else if *self.config_flags.get("build_cli").unwrap_or(&false) {
            println!("CLI initialization logic executed for {}", self.name);
            Ok(()) 
        } else {
            Err(format!("No valid build target specified for {}", self.name))
        }
    }

    fn get_state(&self) -> String {
        let mut state = format!("Component {} initialized.", self.name);
        if *self.config_flags.get("is_enabled").unwrap_or(&false) {
            state.push_str(" (Active)");
        } else {
            state.push_str(" (Disabled)");
        }
        state
    }
}

fn main() {
    let mut web_flags = std::collections::HashMap::new();
    web_flags.insert("build_web".to_string(), true);
    web_flags.insert("is_enabled".to_string(), true);

    let web_component = SystemComponent::new("TrayIcon", web_flags);
    match web_component.setup() {
        Ok(_) => println!("State: {}", web_component.get_state()),
        Err(e) => eprintln!("{}", e),
    }

    let mut cli_flags = std::collections::HashMap::new();
    cli_flags.insert("build_cli".to_string(), true);
    cli_flags.insert("is_enabled".to_string(), false);

    let cli_component = SystemComponent::new("BackgroundService", cli_flags);
    match cli_component.setup() {
        Ok(_) => println!("State: {}", cli_component.get_state()),
        Err(e) => eprintln!("{}", e),
    }
}

use std::collections::HashMap;

struct DeviceConfig {
    usb_enabled: bool,
    ble_enabled: bool,
}

impl Default for DeviceConfig {
    fn default() -> Self {
        DeviceConfig { 
            usb_enabled: true, 
            ble_enabled: false,
        }
    }
}

struct DriverModel {
    name: String,
    config: DeviceConfig,
}

impl DriverModel {
    fn new(name: String) -> Self {
        DriverModel { 
            name, 
            config: DeviceConfig::default(),
        }
    }

    fn set_hardware_support(&mut self, usb: bool, ble: bool) {
        self.config.usb_enabled = usb;
        self.config.ble_enabled = ble;
    }

    fn initialize_callbacks(&self) -> HashMap<String, String> {
        let mut handlers = HashMap::new();

        if self.config.usb_enabled {
            handlers.insert("on_connect".to_string(), "USB Handshake complete".to_string());
        }

        if self.config.ble_enabled {
            handlers.insert("on_scan".to_string(), "BLE Advertising started".to_string());
        }

        if self.config.usb_enabled && self.config.ble_enabled {
            handlers.insert("on_full_init".to_string(), "Both protocols initialized".to_string());
        }

        handlers
    }
}

fn main() {
    let mut driver1 = DriverModel::new("Keyboard Input".to_string());
    driver1.set_hardware_support(true, false);
    println!("--- Initializing Device 1 (USB Only) ---");
    let handlers1 = driver1.initialize_callbacks();
    for (event, message) in &handlers1 {
        println!("{}: {}", event, message);
    }

    let mut driver2 = DriverModel::new("Sensor Array".to_string());
    driver2.set_hardware_support(false, true); // Simulate a build flag change
    println!("n--- Initializing Device 2 (BLE Only) ---");
    let handlers2 = driver2.initialize_callbacks();
    for (event, message) in &handlers2 {
        println!("{}: {}", event, message);
    }
}
